import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { Check, X, Loader2, Eye, MapPin } from "lucide-react";
import { toast } from "sonner";
import { Link } from "react-router-dom";

const AdminLandmarkSubmissions = () => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [statusFilter, setStatusFilter] = useState("pending_review");
  const [rejectDialog, setRejectDialog] = useState<any>(null);
  const [rejectNote, setRejectNote] = useState("");

  const { data: submissions = [], isLoading } = useQuery({
    queryKey: ["admin-landmark-submissions", statusFilter],
    queryFn: async () => {
      let query = (supabase
        .from("restaurants")
        .select("id, name, name_en, address, image_url, created_by, created_at, submission_status, is_draft, visible")
        .eq("template", "landmark")
        .order("created_at", { ascending: false })
        .limit(100)) as any;

      if (statusFilter === "pending_review") {
        query = query.eq("submission_status", "pending_review");
      } else if (statusFilter === "approved") {
        query = query.eq("submission_status", "approved");
      } else if (statusFilter === "rejected") {
        query = query.eq("submission_status", "rejected");
      }
      // "all" shows all user-submitted (has created_by)
      query = query.not("created_by", "is", null);

      const { data, error } = await query;
      if (error) throw error;
      return (data || []) as any[];
    },
  });

  // Fetch submitter profiles
  const userIds = [...new Set(submissions.map((s: any) => s.created_by).filter(Boolean))];
  const { data: profiles = [] } = useQuery({
    queryKey: ["submitter-profiles", userIds],
    queryFn: async () => {
      if (userIds.length === 0) return [];
      const { data } = await supabase
        .from("profiles")
        .select("id, display_name")
        .in("id", userIds);
      return data || [];
    },
    enabled: userIds.length > 0,
  });

  const getSubmitterName = (userId: string) => {
    const p = profiles.find((pr: any) => pr.id === userId);
    return p?.display_name || userId.slice(0, 8);
  };

  const approveMutation = useMutation({
    mutationFn: async (id: string) => {
      // Approve: publish the landmark
      const { error } = await supabase
        .from("restaurants")
        .update({
          submission_status: "approved",
          visible: true,
          is_draft: false,
          draft_expires_at: null,
        } as any)
        .eq("id", id);
      if (error) throw error;

      // Award 100 points
      const submission = submissions.find((s: any) => s.id === id);
      if (submission?.created_by) {
        const { data: profile } = await supabase
          .from("profiles")
          .select("points")
          .eq("id", submission.created_by)
          .single();
        if (profile) {
          await supabase
            .from("profiles")
            .update({ points: (profile.points || 0) + 100 })
            .eq("id", submission.created_by);
        }

        // Notify user
        await supabase.from("notifications").insert({
          user_id: submission.created_by,
          type: "landmark_edit" as any,
          title: `[[MULTILANG]]${JSON.stringify({ zh: "景点审核通过", en: "Landmark Approved", pt: "Ponto turístico aprovado" })}`,
          content: `[[MULTILANG]]${JSON.stringify({ zh: `您提交的景点「${submission.name}」已通过审核并发布，获得 100 积分！`, en: `Your submitted landmark "${submission.name}" has been approved and published. You earned 100 points!`, pt: `O ponto turístico "${submission.name}" que enviou foi aprovado e publicado. Ganhou 100 pontos!` })}`,
          link: `/landmark/${id}`,
          read: false,
        });

        // Check and award landmark badges
        await supabase.rpc("check_and_award_badges", { p_user_id: submission.created_by });
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-landmark-submissions"] });
      toast.success(t("admin.landmarkSubmissions.approveSuccess", "已通过并发布"));
    },
  });

  const rejectMutation = useMutation({
    mutationFn: async ({ id, note }: { id: string; note: string }) => {
      const { error } = await supabase
        .from("restaurants")
        .update({ submission_status: "rejected" } as any)
        .eq("id", id);
      if (error) throw error;

      const submission = submissions.find((s: any) => s.id === id);
      if (submission?.created_by) {
        const noteText = note ? ` ${note}` : "";
        await supabase.from("notifications").insert({
          user_id: submission.created_by,
          type: "landmark_edit" as any,
          title: `[[MULTILANG]]${JSON.stringify({ zh: "景点审核未通过", en: "Landmark Rejected", pt: "Ponto turístico rejeitado" })}`,
          content: `[[MULTILANG]]${JSON.stringify({ zh: `您提交的景点「${submission.name}」未通过审核。${noteText}`, en: `Your submitted landmark "${submission.name}" was rejected.${noteText}`, pt: `O ponto turístico "${submission.name}" que enviou foi rejeitado.${noteText}` })}`,
          link: `/landmark/${id}`,
          read: false,
        });
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-landmark-submissions"] });
      toast.success(t("admin.landmarkSubmissions.rejectSuccess", "已拒绝"));
      setRejectDialog(null);
      setRejectNote("");
    },
  });

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending_review": return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 border-yellow-200">{t("admin.landmarkSubmissions.pendingReview", "待审核")}</Badge>;
      case "approved": return <Badge className="bg-green-100 text-green-700 border-green-200">{t("admin.landmarkSubmissions.approved", "已通过")}</Badge>;
      case "rejected": return <Badge variant="destructive">{t("admin.landmarkSubmissions.rejected", "已拒绝")}</Badge>;
      default: return <Badge variant="secondary">{status}</Badge>;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">{t("admin.landmarkSubmissions.title", "景点推荐审核")}</h1>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-[150px]">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{t("admin.landmarkSubmissions.all", "全部")}</SelectItem>
            <SelectItem value="pending_review">{t("admin.landmarkSubmissions.pendingReview", "待审核")}</SelectItem>
            <SelectItem value="approved">{t("admin.landmarkSubmissions.approved", "已通过")}</SelectItem>
            <SelectItem value="rejected">{t("admin.landmarkSubmissions.rejected", "已拒绝")}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Card>
        <CardContent className="p-0">
          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
            </div>
          ) : submissions.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              {t("admin.landmarkSubmissions.empty", "暂无提交记录")}
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>{t("admin.landmarkSubmissions.photo", "照片")}</TableHead>
                  <TableHead>{t("admin.landmarkSubmissions.name", "名称")}</TableHead>
                  <TableHead>{t("admin.landmarkSubmissions.address", "地址")}</TableHead>
                  <TableHead>{t("admin.landmarkSubmissions.submitter", "提交者")}</TableHead>
                  <TableHead>{t("admin.landmarkSubmissions.status", "状态")}</TableHead>
                  <TableHead>{t("admin.landmarkSubmissions.date", "日期")}</TableHead>
                  <TableHead className="w-40">{t("admin.landmarkSubmissions.actions", "操作")}</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {submissions.map((s: any) => (
                  <TableRow key={s.id}>
                    <TableCell>
                      {s.image_url ? (
                        <img src={s.image_url} alt="" className="w-12 h-12 rounded object-cover" />
                      ) : (
                        <div className="w-12 h-12 rounded bg-muted flex items-center justify-center">
                          <MapPin className="w-4 h-4 text-muted-foreground" />
                        </div>
                      )}
                    </TableCell>
                    <TableCell className="font-medium max-w-[150px] truncate">
                      {s.name}
                    </TableCell>
                    <TableCell className="text-sm max-w-[200px] truncate text-muted-foreground">
                      {s.address}
                    </TableCell>
                    <TableCell className="text-sm">
                      {getSubmitterName(s.created_by)}
                    </TableCell>
                    <TableCell>{getStatusBadge(s.submission_status)}</TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {new Date(s.created_at).toLocaleDateString()}
                    </TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <Link to={`/landmark/${s.id}`} target="_blank">
                          <Button size="sm" variant="ghost" className="h-7 px-2">
                            <Eye className="w-3.5 h-3.5" />
                          </Button>
                        </Link>
                        {s.submission_status === "pending_review" && (
                          <>
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-7 px-2 text-green-600"
                              onClick={() => approveMutation.mutate(s.id)}
                              disabled={approveMutation.isPending}
                            >
                              <Check className="w-3.5 h-3.5" />
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-7 px-2 text-destructive"
                              onClick={() => { setRejectDialog(s); setRejectNote(""); }}
                            >
                              <X className="w-3.5 h-3.5" />
                            </Button>
                          </>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Reject dialog */}
      <Dialog open={!!rejectDialog} onOpenChange={() => setRejectDialog(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.landmarkSubmissions.rejectTitle", "拒绝景点提交")}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <div className="text-sm">
              <span className="text-muted-foreground">{t("admin.landmarkSubmissions.name", "名称")}:</span> {rejectDialog?.name}
            </div>
            <Textarea
              value={rejectNote}
              onChange={(e) => setRejectNote(e.target.value)}
              placeholder={t("admin.landmarkSubmissions.rejectReason", "拒绝原因（可选）")}
              className="min-h-[80px]"
            />
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setRejectDialog(null)}>
              {t("common.cancel")}
            </Button>
            <Button
              variant="destructive"
              onClick={() => rejectMutation.mutate({ id: rejectDialog.id, note: rejectNote })}
              disabled={rejectMutation.isPending}
            >
              {t("admin.landmarkSubmissions.confirmReject", "确认拒绝")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default AdminLandmarkSubmissions;
